/// <summary>
/// extension class for form ITMTable datasource ITMTable
/// </summary>
[ExtensionOf(formDataSourcestr(ITMTable, ITMTable))]
internal final class ETGITMTableFormDS_Extension
{
}

Method.Source:
/// <summary>
/// update design for outbound orders
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    this.updateDesignOutbound();

    return ret;
}

/// <summary>
/// update design for outbound orders
/// </summary>
public void updateDesignOutbound()
{
    ITMLine             itmLineLoc;
    boolean             enableOutboundDesign;
    FormDataSource      formDS          = this;
    ITMTable            itmTableCurrent = formDS.cursor();

    if(itmTableCurrent.ETGLandedCostType == ETGLandedCostType::Outbound && ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::Yes)
    {
        enableOutboundDesign = true;
    }

    formDS.allowCreate(!enableOutboundDesign);
    element.design().controlName(formControlStr(ITMTable, ITMEditor)).visible(!enableOutboundDesign);
    element.design().controlName(formControlStr(ITMTable, ManagePurchaseOrderGroup)).visible(!enableOutboundDesign);
    element.design().controlName(formControlStr(ITMTable, ETGManageSalesOrderGroup)).visible(enableOutboundDesign);
    element.design().showNewButton(!enableOutboundDesign);

    if(enableOutboundDesign)
    {
        select firstonly ETGOUTTransType from itmLineLoc where itmLineLoc.ShipId == itmTableCurrent.ShipId;
        element.design().controlName(formControlStr(ITMTable, ETGOUTTransType)).visible(itmLineLoc.ETGOUTTransType == InventTransType::TransferOrderShip);
        element.design().controlName(formControlStr(ITMTable, ITMLine_TransType)).visible(itmLineLoc.ETGOUTTransType != InventTransType::TransferOrderShip);
    }
}
